    // For each possible k, check if we can sort the array using swaps allowed by k
    for (let k = n - 1; k >= 0; k--) {
        const visited = new Array(n).fill(false);
        let canSort = true;

        for (let i = 0; i < n; i++) {
            if (visited[i]) continue;
            const target = sorted[i];
            let j = i;
            while (j < n) {
                if (nums[j] === target) {
                    // Swap i and j
                    [nums[i], nums[j]] = [nums[j], nums[i]];
                    visited[i] = true;
                    visited[j] = true;
                    break;
                }
                // Check if we can swap nums[i] with nums[j] using k
                if ((nums[i] & nums[j]) === k) {
                    // Swap i and j
                    [nums[i], nums[j]] = [nums[j], nums[i]];
                    visited[i] = true;
                    visited[j] = true;
                    break;
                }
                j++;
            }
        }

        // Check if the array is sorted
        for (let i = 0; i < n - 1; i++) {
            if (nums[i] > nums[i + 1]) {
                canSort = false;
                break;
            }
        }

        if (canSort) {
            return k;
        }
    }

    return 0;
}

